append_guard("src/calculations/gochara.py", '\n# Guru Sade Sati modulation (XI-D)\ndef guru_modulates_sade_sati(natal_moon_si: int, jupiter_transit_si: int) -> bool:\n    """Jupiter adjacent to or aspecting natal Moon during Sade Sati mitigates it.\n    Source: Classical Gochara texts; K.N. Rao references"""\n    house_from_moon = ((jupiter_transit_si - natal_moon_si) % 12) + 1\n    return house_from_moon in {1, 2, 12, 5, 9}  # adjacent or trine\n', "guru_modulates_sade_sati")
append_guard("src/calculations/nakshatra.py", '\n# Abhijit Nakshatra (XII-C) — 28th intercalary nakshatra\n# Location: 6°40\' to 10°53\'20" in Capricorn (sidereal)\n# Source: PVRNR BPHS; used in Muhurtha and Kalachakra\nABHIJIT_START_LON = 9 * 30 + 6 + 40/60     # ~276.667°\nABHIJIT_END_LON   = 9 * 30 + 10 + 53/60 + 20/3600  # ~280.889°\n\ndef is_abhijit_nakshatra(longitude: float) -> bool:\n    """Returns True if longitude falls in Abhijit nakshatra (Capricorn 6°40\'-10°53\'20")."""\n    lon = longitude % 360\n    return ABHIJIT_START_LON <= lon <= ABHIJIT_END_LON\n', "ABHIJIT_START_LON")
